features.snippet:
interface intf(input clk);
  logic a;
endinterface

module top;
  intf intf_i(.clk(clk));
  virtual intf vif;
  initial vif = intf_i;
  assign vif.a = 1'b0; // Illegal per IEEE - virtual interface members cannot be driven via continuous assignment
endmodule

interface intf(input clk);
  logic [7:0] data;
endinterface

module top;
  intf intf_i(.clk(clk));
  virtual intf vif;
  logic [7:0] out;
  initial vif = intf_i;
  always_comb out = vif.data; // Virtual interface members are handles, not compile-time known signals
endmodule

interface intf(input clk);
  logic [7:0] data;
  logic valid;
endinterface

module top;
  intf intf_i(.clk(clk));
  virtual intf vif;
  initial vif = intf_i;
  // Per-member triggers allow scheduling only combinational logic dependent on vif.data
endmodule
